class Solution:
    def binaryGap(self, n: int) -> int:
        max_gap = 0
        prev_one = -1
        while n:
            if n & 1:
                if prev_one != -1:
                    max_gap = max(max_gap, n - prev_one - 1)
                prev_one = n
            n >>= 1
        return max_gap

